// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }
debugger;
	var toastMsg = '';
	var strSuspenseDate = g_form.getValue('suspense_date');
	var dteSuspenseDate = getDateFromFormat(strSuspenseDate, g_user_date_time_format);
	var strExternalDueDate = g_form.getValue('u_external_due_date');
	var dteExternalDueDate = getDateFromFormat(strExternalDueDate, g_user_date_time_format);
	g_form.hideFieldMsg('suspense_date', true);
	g_form.hideFieldMsg('u_external_due_date', true);

	// STRY0077867
	if(!g_form.getValue('parent')){
		if(g_form.getValue('tasking_authority.u_external_flag') == 'true'){
			if(dteSuspenseDate > dteExternalDueDate){
				g_form.showFieldMsg('suspense_date', getMessage('Suspense Date AFTER External Due Date'), 'error', true);
			}
		} else if(g_form.getValue('outbound') == 'true'){
			// STRY0077947
			if(dteExternalDueDate > dteSuspenseDate){
				g_form.showFieldMsg('u_external_due_date', getMessage('External Due Date is AFTER the Suspense Date'), 'error', true);
			}
		}
	} else if(g_form.getValue('outbound') == 'true'){
		// STRY0077947
		if(dteExternalDueDate > dteSuspenseDate){
			g_form.showFieldMsg('u_external_due_date', getMessage('External Due Date is AFTER the Suspense Date'), 'error', true);
		}
	}

}
